def fib(n: int) -> int:
    """
    Returns the nth Fibonacci number using memoization.

    Args:
        n: The index of the Fibonacci number to return (n >= 0).

    Returns:
        The nth Fibonacci number.
    """
    if n < 0:
        raise ValueError("Input must be a non-negative integer.")

    # Initialize the memoization dictionary (cache)
    memo = {}

    def fib_recursive(k):
        # Base cases
        if k == 0:
            return 0
        if k == 1:
            return 1

def binary_search(arr, target):
    left, right = 0, len(arr) - 1  # Correct initialization for right boundary
    while left <= right:           # Loop condition should be left <= right
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1         # Move left boundary past mid
        else:
            right = mid - 1        # Move right boundary before mid
    return -1

def step1(data: list[int]) -> list[int]:
    """Doubles every element in the input list."""
    return [x * 2 for x in data]

def step2(data: list[int]) -> list[int]:
    """Filters the list, keeping only elements greater than 4."""
    return [x for x in data if x > 4]

def step3(data: list[int]) -> int:
    """Sums all elements in the input list."""
    return sum(data)

def process_pipeline_sync(data: list[int]) -> int:
    """
    Processes the data through the pipeline synchronously.

