def binary_search(arr, target):
    left, right = 0, len(arr) - 1  # Correct initialization for right boundary
    while left <= right:           # Loop condition should be left <= right
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1         # Move left boundary past mid
        else:
            right = mid - 1        # Move right boundary before mid
    return -1

def step1(data: list[int]) -> list[int]:
    """Doubles every element in the input list."""
    return [x * 2 for x in data]

def step2(data: list[int]) -> list[int]:
    """Filters the list, keeping only elements greater than 4."""
    return [x for x in data if x > 4]

